// MonoFSRouterServer is the server API for MonoFSRouter service.
// All implementations must embed UnimplementedMonoFSRouterServer
// for forward compatibility.
//
// MonoFSRouter is the coordinator service that provides cluster topology
type MonoFSRouterServer interface {
	// GetClusterInfo returns the list of backend nodes for sharding
	GetClusterInfo(context.Context, *ClusterInfoRequest) (*ClusterInfoResponse, error)
	// Heartbeat for node health checking
	Heartbeat(context.Context, *HeartbeatRequest) (*HeartbeatResponse, error)
	// IngestRepository triggers repository ingestion across the cluster (streaming progress)
	IngestRepository(*IngestRequest, grpc.ServerStreamingServer[IngestProgress]) error
	// NotifyRepositoryIngested is called by nodes when they complete repository ingestion
	NotifyRepositoryIngested(context.Context, *NotifyRepositoryIngestedRequest) (*NotifyRepositoryIngestedResponse, error)
	// DeleteRepository removes a repository from all nodes (cleanup from memory and disk)
	DeleteRepository(context.Context, *DeleteRepositoryRequest) (*DeleteRepositoryResponse, error)
	// GetNodeForFile returns the correct node for a file with fallback support (handles rebalancing)
	GetNodeForFile(context.Context, *GetNodeForFileRequest) (*GetNodeForFileResponse, error)
	// Client lifecycle management
	RegisterClient(context.Context, *RegisterClientRequest) (*RegisterClientResponse, error)
	UnregisterClient(context.Context, *UnregisterClientRequest) (*UnregisterClientResponse, error)
	ClientHeartbeat(context.Context, *ClientHeartbeatRequest) (*ClientHeartbeatResponse, error)
	ListClients(context.Context, *ListClientsRequest) (*ListClientsResponse, error)
	// Graceful failover
	RequestFailover(context.Context, *FailoverRequest) (*FailoverResponse, error)
	// Get files owned by a specific node (used for failover sync)
	GetNodeFiles(context.Context, *GetNodeFilesRequest) (*GetNodeFilesResponse, error)
	// Statistics and monitoring
	GetClusterStats(context.Context, *ClusterStatsRequest) (*ClusterStatsResponse, error)
	GetNodeStats(context.Context, *NodeStatsRequest) (*NodeStatsResponse, error)
	// Cluster maintenance
	DrainCluster(context.Context, *DrainClusterRequest) (*DrainClusterResponse, error)
	UndrainCluster(context.Context, *UndrainClusterRequest) (*UndrainClusterResponse, error)
	// Guardian partition management
	DeleteGuardianFile(context.Context, *DeleteGuardianFileRequest) (*DeleteGuardianFileResponse, error)
	DeleteGuardianDirectory(context.Context, *DeleteGuardianDirectoryRequest) (*DeleteGuardianDirectoryResponse, error)
	// InjectGuardianPartition directly writes inline YAML files into the cluster
	// for a guardian partition. The caller must supply a valid guardian_token.
	// Files become immediately visible on all FUSE mounts at guardian/<partition>/.
	InjectGuardianPartition(context.Context, *InjectGuardianPartitionRequest) (*InjectGuardianPartitionResponse, error)
	UpsertGuardianPaths(context.Context, *UpsertGuardianPathsRequest) (*UpsertGuardianPathsResponse, error)
	DeleteGuardianPaths(context.Context, *DeleteGuardianPathsRequest) (*DeleteGuardianPathsResponse, error)
	ListGuardianVersions(context.Context, *ListGuardianVersionsRequest) (*ListGuardianVersionsResponse, error)
	GetGuardianVersion(context.Context, *GetGuardianVersionRequest) (*GetGuardianVersionResponse, error)
	SubscribeGuardianChanges(*SubscribeGuardianChangesRequest, grpc.ServerStreamingServer[GuardianChangeEvent]) error
	// Doctor Partition operations — telemetry ingest and query
	StreamQueryLogs(*QueryLogsRequest, grpc.ServerStreamingServer[QueryResultItem]) error
	StreamQueryMetrics(*QueryMetricsRequest, grpc.ServerStreamingServer[QueryResultItem]) error
	StreamQueryTraces(*QueryTracesRequest, grpc.ServerStreamingServer[QueryResultItem]) error
	QueryLogs(context.Context, *QueryLogsRequest) (*QueryLogsResponse, error)
	QueryMetrics(context.Context, *QueryMetricsRequest) (*QueryMetricsResponse, error)
	QueryTraces(context.Context, *QueryTracesRequest) (*QueryTracesResponse, error)
	IngestLogs(context.Context, *IngestLogsRequest) (*IngestLogsResponse, error)
	IngestMetrics(context.Context, *IngestMetricsRequest) (*IngestMetricsResponse, error)
	IngestTraces(context.Context, *IngestTracesRequest) (*IngestTracesResponse, error)
	// Ingestion whitelist management
	AddWhitelistedClient(context.Context, *AddWhitelistedClientRequest) (*AddWhitelistedClientResponse, error)
	RemoveWhitelistedClient(context.Context, *RemoveWhitelistedClientRequest) (*RemoveWhitelistedClientResponse, error)
	ListWhitelistedClients(context.Context, *ListWhitelistedClientsRequest) (*ListWhitelistedClientsResponse, error)
	SetWhitelistEnabled(context.Context, *SetWhitelistEnabledRequest) (*SetWhitelistEnabledResponse, error)
	GetWhitelistStatus(context.Context, *GetWhitelistStatusRequest) (*GetWhitelistStatusResponse, error)
	// SubscribeToChanges streams file-change events for a storage ID.
	// Used by Guardian to watch for intent and partition YAML mutations.
	SubscribeToChanges(*SubscribeChangesRequest, grpc.ServerStreamingServer[ChangeEvent]) error
	// Workspace sync orchestration for virtual monorepo publish and refresh flows.
	UploadWorkspaceBundle(grpc.ClientStreamingServer[WorkspaceBundleChunk, UploadWorkspaceBundleResponse]) error
	UploadWorkspaceCommitBundle(grpc.ClientStreamingServer[WorkspaceBundleChunk, UploadWorkspaceBundleResponse]) error
	PublishWorkspace(*PublishWorkspaceRequest, grpc.ServerStreamingServer[WorkspaceSyncEvent]) error
	PushWorkspaceCommits(*PushWorkspaceCommitsRequest, grpc.ServerStreamingServer[WorkspaceSyncEvent]) error
	RefreshWorkspace(*RefreshWorkspaceRequest, grpc.ServerStreamingServer[WorkspaceSyncEvent]) error
	GetWorkspaceSyncJob(context.Context, *GetWorkspaceSyncJobRequest) (*WorkspaceSyncJob, error)
	ListWorkspaceSyncJobs(context.Context, *ListWorkspaceSyncJobsRequest) (*ListWorkspaceSyncJobsResponse, error)
	CancelWorkspaceSyncJob(context.Context, *CancelWorkspaceSyncJobRequest) (*CancelWorkspaceSyncJobResponse, error)
	mustEmbedUnimplementedMonoFSRouterServer()
}

